content:
  // Backpressure all read address phases (including write/read overlap).
  // Using ahb_rd_valid here misses overlap reads and lets the master sample
  // stale HRDATA one cycle too early.
  assign hreadyout = rd_wait ? 1'b1 : !ahb_rd;
  assign hresp     = 1'b0;

endmodule

`default_nettype wire

